public int minFallingPathSum(int[][] matrix) {
    int n = matrix.length;
    for (int i = 1; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            int min_val = matrix[i - 1][j];
            if (j > 0) min_val = Math.min(min_val, matrix[i - 1][j - 1]);
